"""sklearn.semi_supervised — Semi-supervised label propagation."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin


def _rbf_affinity(X, gamma=20):
    sq_dist = np.sum(X ** 2, axis=1, keepdims=True) + \
              np.sum(X ** 2, axis=1) - 2 * X @ X.T
    return np.exp(-gamma * np.maximum(sq_dist, 0))


class LabelPropagation(BaseEstimator, ClassifierMixin):
    """Label Propagation semi-supervised classifier.

    Parameters
    ----------
    kernel : str, default='rbf'
    gamma : float, default=20
    max_iter : int, default=30
    tol : float, default=1e-3
    """

    def __init__(self, kernel='rbf', gamma=20, max_iter=30, tol=1e-3):
        self.kernel = kernel
        self.gamma = gamma
        self.max_iter = max_iter
        self.tol = tol

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        self.classes_ = np.unique(y[y != -1])
        n = X.shape[0]
        n_classes = len(self.classes_)

        # Affinity
        W = _rbf_affinity(X, self.gamma)
        np.fill_diagonal(W, 0)
        D_inv = 1.0 / (W.sum(axis=1, keepdims=True) + 1e-15)
        T = W * D_inv  # transition matrix

        # Label matrix
        Y = np.zeros((n, n_classes))
        labeled = y != -1
        for i, c in enumerate(self.classes_):
            Y[y == c, i] = 1.0
        Y_static = Y.copy()

        for _ in range(self.max_iter):
            Y_new = T @ Y
            # Clamp labelled
            Y_new[labeled] = Y_static[labeled]
            if np.abs(Y_new - Y).max() < self.tol:
                break
            Y = Y_new

        self.label_distributions_ = Y
        self.X_train_ = X
        return self

    def predict(self, X):
        return self.classes_[np.argmax(self.predict_proba(X), axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        W = np.exp(-self.gamma * (
            np.sum(X ** 2, axis=1, keepdims=True) +
            np.sum(self.X_train_ ** 2, axis=1) -
            2 * X @ self.X_train_.T
        ))
        D_inv = 1.0 / (W.sum(axis=1, keepdims=True) + 1e-15)
        T = W * D_inv
        probs = T @ self.label_distributions_
        sums = probs.sum(axis=1, keepdims=True)
        sums[sums == 0] = 1
        return probs / sums


class LabelSpreading(BaseEstimator, ClassifierMixin):
    """Label Spreading semi-supervised classifier.

    Parameters
    ----------
    kernel : str, default='rbf'
    gamma : float, default=20
    alpha : float, default=0.2
    max_iter : int, default=30
    tol : float, default=1e-3
    """

    def __init__(self, kernel='rbf', gamma=20, alpha=0.2, max_iter=30, tol=1e-3):
        self.kernel = kernel
        self.gamma = gamma
        self.alpha = alpha
        self.max_iter = max_iter
        self.tol = tol

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        self.classes_ = np.unique(y[y != -1])
        n = X.shape[0]
        n_classes = len(self.classes_)

        W = _rbf_affinity(X, self.gamma)
        np.fill_diagonal(W, 0)
        D_sqrt_inv = np.diag(1.0 / (np.sqrt(W.sum(axis=1)) + 1e-15))
        S = D_sqrt_inv @ W @ D_sqrt_inv

        Y = np.zeros((n, n_classes))
        for i, c in enumerate(self.classes_):
            Y[y == c, i] = 1.0
        Y_static = Y.copy()

        for _ in range(self.max_iter):
            Y_new = self.alpha * S @ Y + (1 - self.alpha) * Y_static
            if np.abs(Y_new - Y).max() < self.tol:
                break
            Y = Y_new

        self.label_distributions_ = Y
        self.X_train_ = X
        return self

    def predict(self, X):
        return self.classes_[np.argmax(self.predict_proba(X), axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        W = np.exp(-self.gamma * (
            np.sum(X ** 2, axis=1, keepdims=True) +
            np.sum(self.X_train_ ** 2, axis=1) -
            2 * X @ self.X_train_.T
        ))
        D_inv = 1.0 / (W.sum(axis=1, keepdims=True) + 1e-15)
        T = W * D_inv
        probs = T @ self.label_distributions_
        sums = probs.sum(axis=1, keepdims=True)
        sums[sums == 0] = 1
        return probs / sums
